(1, 'Sergey Brin', 'Sergey Mikhailovich Brin is an American business magnate, computer scientist, and Internet entrepreneur. Together with Larry Page, he co-founded Google. Brin was the president of Google`s parent company, Alphabet Inc., until stepping down from the role on December 3, 2019.', 'Alphabet Inc.', 'Co-Founder', 'sergey@gmail.com', 'https://abc.xyz/', '+1 (650) 253-0000', 'Mountain View, California', '2022-02-25 10:23:38'),
(2, 'Jeff Bezos', 'Jeffrey Preston Bezos is an American entrepreneur, media proprietor, investor, computer engineer, and commercial astronaut. He is the founder and executive chairman of Amazon, where he previously served as the president and CEO.', 'Amazon.com, Inc. ', 'CEO', 'jeff@amazon.com', 'Amazon.com', '1-206-266-1000', 'Seattle, Washington', '2022-02-25 10:28:19'),
(3, 'Mark Zuckerberg', 'Mark Elliot Zuckerberg is an American media magnate, internet entrepreneur, and philanthropist. He is known for co-founding the social media website Facebook and its parent company Meta Platforms, of which he is the chairman, chief executive officer, and controlling shareholder.', 'Meta Platforms', 'Co-Founder', 'mark@facebook.com', 'Facebook.com', '650-543-4800', 'Menlo Park, California', '2022-02-25 10:32:01'),
(4, 'Tim Cook', 'Timothy Donald Cook is an American business executive who has been the chief executive officer of Apple Inc. since 2011. Cook previously served as the company`s chief operating officer under its co-founder Steve Jobs.', 'Apple Inc.', 'Chief Executive Officer', 'tim@apple.com', 'Apple.com', '(408) 996â€“1010', 'Cupertino, California', '2022-02-25 10:35:20'),
(5, 'Bill Gates', 'William Henry Gates III is an American business magnate, software developer, investor, author, and philanthropist. He is a co-founder of Microsoft, along with his late childhood friend Paul Allen.', 'Microsoft Corporation', 'Co-Founder', 'bill.gates@microsoft.com', 'https://www.gatesnotes.com/', '(206) 709-3400', 'Redmond, Washington', '2022-02-25 10:39:25');

